def encode(message):
    vowels = "aeiouAEIOU"
    result = []

    for ch in message:
        if ch in vowels:
            shifted = chr(ord(ch.lower()) + 2)
            result.append(shifted.swapcase() if ch.islower() else shifted)
        else:
            result.append(ch.swapcase())

    return "".join(result)
